<?php namespace App\Repositories\Assessment;use App\Repositories\BaseRepository;use App\Models\Assessment\ExamSchedule;use Illuminate\Database\Eloquent\Collection;class ExamScheduleRepository extends BaseRepository{    public function __construct(ExamSchedule $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByExam(int $examId): Collection    {        return $this->findByField('exam_id', $examId);    }    public function findBySubject(int $subjectId): Collection    {        return $this->findByField('subject_id', $subjectId);    }    public function findByClass(int $classId): Collection    {        return $this->findByField('class_id', $classId);    }    public function getByDate(string $date): Collection    {        return $this->query()->whereDate('exam_date', $date)->get();    }    public function getByDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('exam_date', [$startDate, $endDate])->orderBy('exam_date', 'asc')->get();    }    public function getScheduleByExamAndClass(int $examId, int $classId): Collection    {        return $this->query()->where('exam_id', $examId)->where('class_id', $classId)->orderBy('exam_date', 'asc')->orderBy('start_time', 'asc')->get();    }    public function checkConflict(int $classId, string $date, string $startTime, string $endTime, ?int $excludeId = null): bool    {        $query = $this->query()->where('class_id', $classId)->whereDate('exam_date', $date)->where(function ($q) use ($startTime, $endTime) {                $q->whereBetween('start_time', [$startTime, $endTime])->orWhereBetween('end_time', [$startTime, $endTime]);            });        if ($excludeId) {            $query->where('id', '!=', $excludeId);        }        return $query->exists();    }}